import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.il0noOp3.js";const p=JSON.parse('{"title":"Roadmap","description":"Planned features, future enhancements, and the long-term vision for AzureScout.","frontmatter":{"description":"Planned features, future enhancements, and the long-term vision for AzureScout."},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md"}'),n={name:"roadmap.md"};function d(s,e,i,l,c,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p><em>See everything. Own your cloud.</em></p><p>This page outlines what&#39;s planned, what&#39;s in progress, and what&#39;s been delivered. Community contributions are welcome — see <a href="./contributing.html">Contributing</a> to get involved.</p><blockquote><p>The consolidated architecture, work-item index, audit findings, and delivery plan live in the <a href="./design/master-plan.html">Master Design &amp; Plan</a>. This roadmap is the public-facing summary of it.</p></blockquote><h2 id="current-release-—-v2-0-0-—-caf-waf-assessment-platform" tabindex="-1">Current Release — v2.0.0 — CAF/WAF Assessment Platform <a class="header-anchor" href="#current-release-—-v2-0-0-—-caf-waf-assessment-platform" aria-label="Permalink to &quot;Current Release — v2.0.0 — CAF/WAF Assessment Platform&quot;">​</a></h2><p>Released 23 July 2026. Turns AzureScout from an inventory tool into a read-only CAF/WAF landing-zone assessment. Runtime-verified offline (Pester) and against a live Azure tenant.</p><table tabindex="0"><thead><tr><th>Capability</th><th>What shipped</th></tr></thead><tbody><tr><td>Assessment engine</td><td>Declarative YAML rules (JSONPath + assert types), dual CAF/WAF scoring, prioritized gap list — <strong>139 rules across 8 CAF design areas + 5 WAF pillars</strong></td></tr><tr><td>Collect + ingest</td><td>Read-only ARG collect layer (<code>collect.json</code>); native governance collector (v2.1.0) / ARG query pack / Advisor ingest — AzGovViz retained as opt-in only</td></tr><tr><td>ALZ benchmark</td><td>Live tenant diffed against a canonical ALZ reference</td></tr><tr><td>Tiered reporting</td><td>Power BI, self-contained HTML, executive <strong>PowerPoint (OpenXML SDK — no Python)</strong>, Excel + JSON evidence</td></tr><tr><td>Per-domain analytics</td><td>Every discovery category runnable + tagged: <code>Invoke-ScoutAssessment -Assessment &lt;Category&gt;</code></td></tr><tr><td>Entry point</td><td><code>Invoke-ScoutAssessment</code> (run one/some/all), read-only permission pre-flight</td></tr></tbody></table><blockquote><p><strong>Breaking:</strong> introduces the <code>findings.json</code> contract and demotes Excel-first output to an evidence tier. Assessment features require PowerShell 7.</p></blockquote><p>Deferred to v2.1.0: full per-category rule depth (AB#5061–5075). The native governance collector (AB#5041), the fully unattended pipeline (AB#5050), and the React report variant + cross-run drift tracking (AB#5053) have since shipped on <code>main</code> — see <strong>v2.1.0 (in development)</strong> below.</p><h2 id="previous-release-—-v1-0-0" tabindex="-1">Previous Release — v1.0.0 <a class="header-anchor" href="#previous-release-—-v1-0-0" aria-label="Permalink to &quot;Previous Release — v1.0.0&quot;">​</a></h2><p>Released February 2026.</p><table tabindex="0"><thead><tr><th>Area</th><th>What&#39;s included</th></tr></thead><tbody><tr><td>Excel Reports</td><td>171 worksheets (154 ARM + 17 Entra ID) covering all 15 Azure resource categories</td></tr><tr><td>Category Filtering</td><td><code>-Category</code> parameter to scope runs to specific resource types</td></tr><tr><td>AI / ML Coverage</td><td>27 modules: OpenAI, AI Foundry, Azure ML, Cognitive Services, Bot Services, Search</td></tr><tr><td>AVD Coverage</td><td>6 modules: Host Pools, App Groups, Workspaces, Session Hosts, Scaling Plans, Applications</td></tr><tr><td>Arc Coverage</td><td>Sites, SQL Servers, Data Controllers, SQL Managed Instances, Arc-enabled Kubernetes enhancements</td></tr><tr><td>VM &amp; Arc Enrichment</td><td>Backup status, Site Recovery, Update Manager, Advisor score, Monitor metrics, Cost estimates</td></tr><tr><td>Monitor Coverage</td><td>24 modules: Diagnostic settings, alert rules, DCRs, App Insights deep data, autoscale, workbooks</td></tr><tr><td>Markdown / AsciiDoc Export</td><td><code>-OutputFormat Markdown|AsciiDoc</code> generates portable reports alongside Excel/JSON</td></tr><tr><td>Permission Audit</td><td><code>Invoke-AZSCPermissionAudit</code> with ARM + Graph checks, color output, Markdown/AsciiDoc export</td></tr><tr><td>Subscription &amp; MG Completeness</td><td>Captures ALL subscriptions (including empty/disabled) and full MG hierarchy</td></tr><tr><td>Module Naming</td><td>Renamed from <em>AzureTenantInventory</em> to <em>AzureScout</em> (prefix: <code>AZSC</code>)</td></tr></tbody></table><h2 id="near-term-—-v1-1-0" tabindex="-1">Near-term — v1.1.0 <a class="header-anchor" href="#near-term-—-v1-1-0" aria-label="Permalink to &quot;Near-term — v1.1.0&quot;">​</a></h2><p>Focus: quality, reliability, and community onboarding.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Pester test suite</td><td>Full unit + integration tests for all public functions and key private functions</td><td>:blue_circle: Planned</td></tr><tr><td>PSGallery publish</td><td>Publish <code>AzureScout</code> module to PowerShell Gallery</td><td>:blue_circle: Planned</td></tr><tr><td>GitHub Actions CI</td><td>Run Pester tests on PR + push; block merge on failure</td><td>:blue_circle: Planned</td></tr><tr><td>Category alias documentation</td><td>Comprehensive table of all accepted <code>-Category</code> aliases and their canonical names</td><td>:blue_circle: Planned</td></tr><tr><td>Resource provider pre-flight</td><td>Warn before scan when required providers are not registered in a subscription</td><td>:blue_circle: Planned</td></tr><tr><td>Throttling / retry improvements</td><td>Exponential backoff on ARM 429 responses; configurable <code>-ThrottleDelay</code></td><td>:blue_circle: Planned</td></tr><tr><td><code>Invoke-AzureScout -WhatIf</code></td><td>Show which modules would run without actually executing</td><td>:blue_circle: Planned</td></tr><tr><td>Non-destructive cache</td><td>Prevent <code>ReportCache</code> and <code>DiagramCache</code> from being overwritten on subsequent runs. Each invocation writes to a timestamped (or <code>-RunName</code> named) subfolder. Previous scan data is never lost unless <code>-Force</code> is specified. <code>Clear-AZSCCacheFolder -OlderThan &lt;days&gt;</code> for cleanup.</td><td>:blue_circle: Planned</td></tr></tbody></table><h3 id="visual-dashboard-tabs-darkblue-overview-style-worksheets" tabindex="-1">Visual Dashboard Tabs (DarkBlue &quot;overview-style&quot; worksheets) <a class="header-anchor" href="#visual-dashboard-tabs-darkblue-overview-style-worksheets" aria-label="Permalink to &quot;Visual Dashboard Tabs (DarkBlue &quot;overview-style&quot; worksheets)&quot;">​</a></h3><p>Phase 10 added raw data tabs (Cost Management, Security Overview, Azure Update Manager, Azure Monitor) that collect data into flat tables. The next step is to add <strong>visual dashboard tabs</strong> — styled like the Overview sheet (DarkBlue tab color, EPPlus shapes, pivot charts) — that summarize and visualize the data from those raw tabs.</p><table tabindex="0"><thead><tr><th>Dashboard</th><th>Charts / Visualizations</th><th>Status</th></tr></thead><tbody><tr><td>Cost Dashboard</td><td>Cost by Resource Type (bar), Cost by Subscription (pie), Cost by Region (column), Cost by SKU (bar)</td><td>:blue_circle: Planned</td></tr><tr><td>Security Dashboard</td><td>Assessments by Severity (pie), Findings by Subscription (bar), Defender Plans (column), Active Alerts by Severity (bar)</td><td>:blue_circle: Planned</td></tr><tr><td>Update Manager Dashboard</td><td>Machines by Platform (pie), Machines by OS Type (pie), Machines by Region (column), Machines by Power State (bar), Machines by Subscription (bar)</td><td>:blue_circle: Planned</td></tr><tr><td>Monitor Dashboard</td><td>Alert Rules by Subscription (bar), Action Groups by Subscription (pie), DCRs by Subscription (column), App Insights by Subscription (bar)</td><td>:blue_circle: Planned</td></tr></tbody></table><p>Each dashboard tab will:</p><ul><li>Use DarkBlue tab color (matching Overview, Subscriptions, Advisor)</li><li>Be pinned after the Overview sheet group via <code>MoveAfter</code> in the ordering function</li><li>Contain EPPlus pivot tables + charts generated by <code>Build-AZSCDashboardTabs</code></li><li>Only appear when the corresponding raw data tab has data (no empty dashboards)</li></ul><h2 id="medium-term-—-v1-2-0" tabindex="-1">Medium-term — v1.2.0 <a class="header-anchor" href="#medium-term-—-v1-2-0" aria-label="Permalink to &quot;Medium-term — v1.2.0&quot;">​</a></h2><p>Focus: depth, breadth, and multi-tenant scenarios.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Multi-tenant scanning</td><td><code>-TenantID</code> accepts multiple tenant IDs. Authenticates to each tenant sequentially, runs the full extraction → processing → reporting pipeline per tenant. Supports combined workbook (with Tenant column) or separate per-tenant workbooks via <code>-MergeOutput</code> switch. Auth failure on one tenant does not block others. Builds on non-destructive cache (v1.1.0) for run isolation.</td><td>:blue_circle: Planned</td></tr><tr><td>Word document export (#22)</td><td><code>-OutputFormat Word</code> generates a <code>.docx</code> report with cover page, table of contents, per-category sections with summary tables, resource counts, and key metrics. Suitable for client deliverables, executive summaries, and formal documentation.</td><td>:blue_circle: Planned</td></tr><tr><td>PDF report export (#23)</td><td><code>-OutputFormat PDF</code> generates a <code>.pdf</code> report with cover page, table of contents, paginated resource tables, and headers/footers. Ideal for archival, compliance evidence, and stakeholder distribution.</td><td>:blue_circle: Planned</td></tr><tr><td>Cost anomaly detection</td><td>Surface Azure Cost Management anomalies in the Cost Management tab</td><td>💡 Idea</td></tr><tr><td>Bicep / IaC gap detection</td><td>Compare discovered resources against known IaC templates; flag unmanaged resources</td><td>💡 Idea</td></tr><tr><td>Resource drift reporting</td><td>Compare two inventory runs and report what was added, removed, or changed</td><td>💡 Idea</td></tr><tr><td>Azure DevOps integration</td><td>Inventory Azure DevOps organizations, projects, pipelines alongside Azure resources</td><td>💡 Idea</td></tr><tr><td>GitHub Actions module</td><td>Publish as a GitHub Action so pipelines can generate inventory reports without local setup</td><td>💡 Idea</td></tr><tr><td>Fabric / Power BI export (#17)</td><td><code>-OutputFormat PowerBI</code> generates a flat normalized CSV bundle (<code>PowerBI/</code> folder) with <code>_metadata.csv</code>, <code>Subscriptions.csv</code>, per-module <code>Resources_*.csv</code> and <code>Entra_*.csv</code> files, and a <code>_relationships.json</code> star-schema manifest for Power BI Desktop / Microsoft Fabric</td><td>✅ Done</td></tr><tr><td>IoT deep coverage</td><td>IoT Hub device registry, Device Provisioning Service, Digital Twins topology</td><td>💡 Idea</td></tr></tbody></table><h2 id="major-—-v2-0-0-—-caf-waf-assessment-platform-epic-ab-5023-—-delivered" tabindex="-1">Major — v2.0.0 — CAF/WAF Assessment Platform (Epic AB#5023) — Delivered <a class="header-anchor" href="#major-—-v2-0-0-—-caf-waf-assessment-platform-epic-ab-5023-—-delivered" aria-label="Permalink to &quot;Major — v2.0.0 — CAF/WAF Assessment Platform (Epic AB#5023) — Delivered&quot;">​</a></h2><p>Turned inventory into a <strong>scored CAF/WAF landing-zone assessment</strong>. Collection stays as-is; a three-layer, JSON-on-disk architecture (<code>collect.json</code> → <code>findings.json</code> → deliverables) adds assessment and rebuilds reporting. Read-only throughout. <strong>Shipped in v2.0.0 (2026-07-23).</strong></p><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Assessment engine</td><td>Declarative YAML rules (JSONPath + assert types), dual CAF/WAF scoring, prioritized gap list</td><td>✅ Done (AB#5027, AB#5034)</td></tr><tr><td>CAF/WAF rule content</td><td>8 CAF design areas + 5 WAF pillars — 139 rules across 23 version-controlled files</td><td>✅ Done (AB#5031, AB#5057)</td></tr><tr><td>Ingest layer</td><td>Fold an ARG query pack and Advisor into one <code>collect.json</code>; governance now ingested natively by default (see v2.1.0 below) — Azure Governance Visualizer remains available as an opt-in ingestor</td><td>✅ Done (AB#5037)</td></tr><tr><td>ALZ benchmark diff</td><td>Compare the live tenant against a canonical ALZ reference (MG archetypes, required policies)</td><td>✅ Done — engine + native governance collection, no upstream AzGovViz dependency (AB#5041, v2.1.0)</td></tr><tr><td>Tiered reporting</td><td>Power BI (primary), self-contained HTML, executive PPTX (OpenXML SDK); Excel/JSON retained as evidence</td><td>✅ Done (AB#5044)</td></tr><tr><td>Module registry + entry point</td><td><code>-Assessment</code> run one/some/all; read-only permission pre-flight</td><td>✅ Done (AB#5024); unattended one-command pipeline ✅ Done (AB#5050, v2.1.0)</td></tr><tr><td>React report + drift tracking</td><td>Richer React report variant and cross-run score-drift tracking</td><td>✅ Done (AB#5053, v2.1.0)</td></tr></tbody></table><h2 id="major-—-v2-1-0-—-platform-hardening-epic-ab-5023-carryover-—-released-2026-07-23" tabindex="-1">Major — v2.1.0 — Platform Hardening (Epic AB#5023 carryover) — Released 2026-07-23 <a class="header-anchor" href="#major-—-v2-1-0-—-platform-hardening-epic-ab-5023-carryover-—-released-2026-07-23" aria-label="Permalink to &quot;Major — v2.1.0 — Platform Hardening (Epic AB#5023 carryover) — Released 2026-07-23&quot;">​</a></h2><p>Three more Epic AB#5023 capabilities have shipped on <code>main</code> ahead of the full per-domain analytics epic below. Not yet tagged/released — see <a href="https://github.com/thisismydemo/azure-scout/blob/main/RELEASES.md" target="_blank" rel="noreferrer"><code>RELEASES.md</code></a> for status.</p><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Native governance collector</td><td><code>Import-Governance</code> replaces the AzGovViz hard dependency as the <strong>default</strong> governance collector — populates <code>collect.json</code>&#39;s <code>governance</code> object natively from Azure Resource Graph and ambient-token ARM REST, needing only Reader at the management-group root. No cloned repo, no <code>AzAPICall</code> install prompt, fully unattended, StrictMode-safe. Live-verified against the HCS tenant. <code>AzGovViz</code> remains available as an opt-in <code>Ingest</code> value; nothing depends on it by default anymore.</td><td>✅ Done (AB#5041)</td></tr><tr><td>Unattended pipeline</td><td><code>Invoke-ScoutPipeline</code> runs collect → assess → report headless into one dated run folder — non-interactive throughout, runs the read-only permission pre-flight first, and degrades to <code>PartialSuccess</code> (rather than losing output) if an exporter fails. Writes <code>pipeline-summary.json</code>/<code>.md</code>.</td><td>✅ Done (AB#5050)</td></tr><tr><td>React report + cross-run drift</td><td><code>-OutputFormat React</code> renders a single self-contained <code>report-react.html</code> (client-side filter/sort/search, summary dashboard, Drift tab). <code>Get-ScoutDrift</code> computes cross-run New / Resolved / Regressed / Unchanged findings plus a weighted score delta, tracked in an append-only <code>.scout-history/findings-history.json</code>.</td><td>✅ Done (AB#5053)</td></tr></tbody></table><p>Not yet included in this dev line: full per-category rule depth (AB#5061–5075) — tracked below.</p><h2 id="major-—-v2-1-0-—-per-domain-caf-waf-analytics-epic-ab-5056" tabindex="-1">Major — v2.1.0 — Per-Domain CAF/WAF Analytics (Epic AB#5056) <a class="header-anchor" href="#major-—-v2-1-0-—-per-domain-caf-waf-analytics-epic-ab-5056" aria-label="Permalink to &quot;Major — v2.1.0 — Per-Domain CAF/WAF Analytics (Epic AB#5056)&quot;">​</a></h2><p>Focus: extend CAF/WAF analytics to <strong>every</strong> Scout category, not just the landing-zone roll-up. Each of the 15 discovery categories becomes an <strong>independently runnable, categorized and tagged assessment</strong> — so you can run and score <em>just</em> Governance, <em>just</em> Monitoring, <em>just</em> Update Manager, etc.</p><table tabindex="0"><thead><tr><th>Capability</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Assessment taxonomy &amp; tagging</td><td>Manifest gains <code>Category</code> / <code>Frameworks</code> / <code>Tags</code>; <code>-Assessment &lt;Category&gt;</code> runs scoped discovery + scoped scoring; sub-bundles (Governance/Policy/UpdateManager under Management, Monitoring under Monitor)</td><td>:blue_circle: Planned (AB#5057)</td></tr><tr><td>Per-category coverage</td><td>CAF/WAF rule coverage authored for each category — Management, Monitor, Networking, Identity, Security, Compute, Storage, Databases, Containers, Web, Analytics, AI, Integration, Hybrid, IoT</td><td>:blue_circle: Planned (AB#5061–AB#5075)</td></tr><tr><td>Registry document</td><td>A table of every possible assessment: category, sub-bundles, CAF areas, WAF pillars, tags</td><td>:blue_circle: Planned (AB#5057)</td></tr></tbody></table><p>See <a href="https://github.com/thisismydemo/azure-scout/blob/main/RELEASES.md" target="_blank" rel="noreferrer"><code>RELEASES.md</code></a> for the build/release ledger.</p><h2 id="far-future-—-web-version-of-azure-scout-epic-ab-5093" tabindex="-1">Far-future — Web version of Azure Scout (Epic AB#5093) <a class="header-anchor" href="#far-future-—-web-version-of-azure-scout-epic-ab-5093" aria-label="Permalink to &quot;Far-future — Web version of Azure Scout (Epic AB#5093)&quot;">​</a></h2><blockquote><p>A <strong>web-UI version with the same capabilities as the PowerShell version</strong> — same engine, browser instead of terminal. <strong>Far-future, not scheduled.</strong> Only the web-only plumbing (server, runspace, progress polling, launchers) is unique to it. The actual product features are <strong>buildable in the PowerShell version now</strong> (Epic AB#5094) and the web version inherits them.</p></blockquote><blockquote><p><strong>Status: under evaluation — NOT committed.</strong> This is a possible future direction, not planned work, and it would be a <strong>departure from the current &quot;no portals&quot; stance</strong> in the <a href="#long-term-vision">Long-term Vision</a> below. Captured here so the direction is tracked and can be decided deliberately rather than drifting into the backlog.</p></blockquote><p>A <strong>served web-application</strong> as a <strong>second delivery surface</strong> for the same engine — not a different product. It would run a local HTTP listener with a browser UI (background-runspace collection with live progress, interactive vis.js topology, in-browser PDF export, config upload/download). <strong>The web portal must reach FEATURE PARITY with the PowerShell version</strong> — every product feature is available through both surfaces; neither has a feature the other lacks. Only the <em>delivery plumbing</em> below is web-specific. It is weeks of net-new engineering (web server + JS front-end + IPC layer).</p><p><strong>Web delivery surface — plumbing only (Epic AB#5093, exploratory):</strong></p><table tabindex="0"><thead><tr><th>Area</th><th>Web-surface plumbing (no PowerShell equivalent)</th><th>Status</th></tr></thead><tbody><tr><td>Server core</td><td>HTTP listener + background runspace, file-based progress IPC (client polls), named stages %, concurrent-collection guard, cached-inventory serving, runspace disposal, double-poll guard</td><td>💡 Exploratory (AB#381–385, 403, 404)</td></tr><tr><td>Launchers</td><td><code>start.cmd</code> / <code>start.sh</code> to launch the server</td><td>💡 Exploratory (AB#388)</td></tr></tbody></table><h3 id="feature-parity-—-shared-across-both-surfaces-epic-ab-5094" tabindex="-1">Feature parity — shared across both surfaces (Epic AB#5094) <a class="header-anchor" href="#feature-parity-—-shared-across-both-surfaces-epic-ab-5094" aria-label="Permalink to &quot;Feature parity — shared across both surfaces (Epic AB#5094)&quot;">​</a></h3><p>The product <strong>features</strong> below are <strong>not web-only or PowerShell-only — they belong to both surfaces</strong>. They live in the core product and are surfaced through the PowerShell module (CLI + static/React reports) <em>and</em> the web portal. Same capability, per-surface delivery:</p><ul><li><strong>Report visuals</strong> (in the React/HTML report today, and the web portal later): vis.js VNet topology + click-to-details + reset/fit controls, MG-hierarchy diagram, per-section search/filter, clickable rows + side panel, 14 KPI cards, Azure Firewall drill-down, Governance section (budgets/locks/tag chips), policy-enforcement badge, scope tooltips, resources-only JSON evidence export (AB#376–378, 380, 386, 387, 389–393, 396). <em>Several partially exist in the React report already — extend them.</em></li><li><strong>WAF config load/save + report PDF export</strong> (PowerShell via parameters/file output; web via browser upload/download + in-browser render) (AB#373–375, 379, 394, 395).</li><li><strong>Collector / pipeline resilience</strong> (shared engine): per-subscription try/catch/continue, MG role-requirement hint, false RP-registration-error swallow, per-group firewall-parse-error logging, empty-data guard, pipeline-<code>HadErrors</code> warning capture (AB#397–402).</li><li><strong>Live-progress UX</strong> — same feature, per-surface delivery: Spectre.Console TUI in the CLI, browser progress in the web portal (AB#405).</li></ul><h2 id="long-term-vision" tabindex="-1">Long-term Vision <a class="header-anchor" href="#long-term-vision" aria-label="Permalink to &quot;Long-term Vision&quot;">​</a></h2><p>AzureScout aims to be the definitive open-source Azure visibility tool for:</p><ul><li><strong>Architects</strong> — understand the full shape of a tenant before designing changes</li><li><strong>Security teams</strong> — identify misconfigured, unmonitored, or over-privileged resources</li><li><strong>FinOps practitioners</strong> — surface cost waste, reservation opportunities, and untagged resources</li><li><strong>Managed service providers</strong> — generate client-ready reports across multiple tenants</li></ul><p>The tool will remain <strong>open-source, PowerShell-native, and Excel-friendly</strong> — no agents, no portals, no licensing fees.</p><h2 id="completed-phases" tabindex="-1">Completed Phases <a class="header-anchor" href="#completed-phases" aria-label="Permalink to &quot;Completed Phases&quot;">​</a></h2><p>All implementation phases from the original migration plan are complete. See the <a href="./changelog.html">Changelog</a> for the full history.</p><table tabindex="0"><thead><tr><th>Phase</th><th>Summary</th></tr></thead><tbody><tr><td>Phase 1-9</td><td>Core engine, module loading, Excel generation, JSON output, Draw.io diagrams, auth methods, connection handling, permission pre-flight</td></tr><tr><td>Phase 10</td><td>Specialized Excel tabs: Cost Management, Security Overview, Azure Update Manager, Azure Monitor</td></tr><tr><td>Phase 11</td><td>All-subscriptions + full MG hierarchy enumeration</td></tr><tr><td>Phase 12</td><td>ARM-only default scope, permission documentation, README overhaul</td></tr><tr><td>Phase 13</td><td>15 new Azure Monitor/Insights modules</td></tr><tr><td>Phase 14</td><td>15 new AI/ML modules</td></tr><tr><td>Phase 15</td><td>6 AVD modules + AVD on Azure Local/Arc detection</td></tr><tr><td>Phase 16</td><td>Arc site configs, Arc SQL Server, Arc Data Services enhancements</td></tr><tr><td>Phase 17</td><td>VM + Arc deep enrichment (metrics, backup, DR, cost, advisor)</td></tr><tr><td>Phase 18</td><td>Category folder alignment + <code>.CATEGORY</code> metadata parsing</td></tr><tr><td>Phase 19</td><td>Richer progress indicators, clear permission error messages</td></tr><tr><td>Phase 20</td><td><code>Invoke-AZSCPermissionAudit</code> + <code>Test-AZSCPermissions</code> refactor</td></tr><tr><td>Phase 21</td><td>Markdown + AsciiDoc export, <code>Export-AZSCMarkdownReport</code>, <code>Export-AZSCAsciiDocReport</code></td></tr></tbody></table><h2 id="suggest-a-feature" tabindex="-1">Suggest a Feature <a class="header-anchor" href="#suggest-a-feature" aria-label="Permalink to &quot;Suggest a Feature&quot;">​</a></h2><p>Open an issue at <a href="https://github.com/thisismydemo/azure-scout/issues" target="_blank" rel="noreferrer">github.com/thisismydemo/azure-scout/issues</a> with the label <code>enhancement</code>.</p><p>Pull requests are welcome — see <a href="./contributing.html">Contributing</a> for guidelines.</p><h2 id="fork-attribution" tabindex="-1">Fork Attribution <a class="header-anchor" href="#fork-attribution" aria-label="Permalink to &quot;Fork Attribution&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Fork Attribution</p><p><strong>AzureScout is a fork of <a href="https://github.com/microsoft/ARI" target="_blank" rel="noreferrer">Azure Resource Inventory (ARI)</a></strong> by Microsoft, originally created by <a href="https://github.com/Claudio-Merola" target="_blank" rel="noreferrer">Claudio Merola</a> and <a href="https://github.com/RenatoGregio" target="_blank" rel="noreferrer">Renato Gregio</a>. The ARI project provided the entire foundation that AzureScout builds upon — its ARM inventory module set, the draw.io diagram engine, Excel reporting, and more. AzureScout is now at 154 ARM + 17 Entra ID = 171 inventory modules — see <a href="./arm-modules.html">ARM Modules</a> and <a href="./entra-modules.html">Entra ID Modules</a>. We are deeply grateful for their work.</p><p>See <a href="./credits.html">Credits &amp; Attribution</a> for full details, or <a href="./ari-differences.html">Differences from ARI</a> for what has changed.</p></div>',55)])])}const g=t(n,[["render",d]]);export{p as __pageData,g as default};
